let _parsed: Airport[] | null = null;
export function getAirports(): Airport[] {
  if (!_parsed) {
    _parsed = AIRPORTS_RAW.map(([code, name, country, lat, lon]) => ({ code, name, country, lat, lon }));
  }
  return _parsed;
}

let _routePairs: [string, string][] | null = null;
export function getRoutes(): [string, string][] {
  if (!_routePairs) {
    _routePairs = [];
    for (const [src, dests] of Object.entries(ROUTES_ADJ)) {
      for (const dst of dests.split(' ')) {
        _routePairs.push([src, dst]);
      }
    }
  }
  return _routePairs;
}
